      throw messagesError;
    }

    // Delete user's appointments
    const { error: appointmentsError } = await supabase
      .from('appointments')
      .delete()
      .eq('user_id', userId);

    if (appointmentsError) {
      console.error('Error deleting user appointments:', appointmentsError);
      throw appointmentsError;
    }

    // Delete user's anamneses
    const { error: anamnesesError } = await supabase
      .from('anamneses')
      .delete()
      .eq('user_id', userId);

    if (anamnesesError) {
      console.error('Error deleting user anamneses:', anamnesesError);
      throw anamnesesError;
    }

     // Delete user's notifications
     const { error: notificationsError } = await supabase
     .from('user_has_notifications')
     .delete()
     .eq('user_id', userId);

   if (notificationsError) {
     console.error('Error deleting user notifications:', notificationsError);
     throw notificationsError;
   }

    // Finally, delete the user
    const { error: userError } = await supabase
      .from('users')
      .delete()
      .eq('id', userId);

    if (userError) {
      console.error('Error deleting user:', userError);
      throw userError;
    }

    return true; // Deletion successful

  } catch (error) {
    console.error('An error occurred during user deletion:', error);
    throw error; // Re-throw the error to be handled by the caller
  }
}

