import React, { useState, useRef, useEffect } from 'react';
import { Bold, Italic, List, AlignLeft, FilePlus, ChevronDown } from 'lucide-react';

interface Template {
  label: string;
  content: string;
}

interface RichTextEditorProps {
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  templates?: Template[];
  colorTheme?: 'indigo' | 'emerald' | 'amber' | 'blue';
}

export default function RichTextEditor({ 
  value, 
  onChange, 
  placeholder, 
  templates = [],
  colorTheme = 'blue' 
}: RichTextEditorProps) {
  const editorRef = useRef<HTMLDivElement>(null);

  // FIX: Initialize with empty string instead of 'value'. 
  // This ensures that when the component mounts with data (or data arrives shortly after),
  // the useEffect detects a mismatch ("Data" !== "") and updates the DOM.
  const lastHtmlRef = useRef(""); 

  const [showTemplates, setShowTemplates] = useState(false);

  // Sync external value changes to innerHTML ONLY if they come from outside (DB, Template)
  useEffect(() => {
    if (!editorRef.current) return;

    // If the new prop value is different from the last value we processed...
    if (value !== lastHtmlRef.current) {
      // And strictly different from current HTML content...
      if (editorRef.current.innerHTML !== value) {
         // It means it's an external update (e.g. loaded from DB or Template inserted)
         editorRef.current.innerHTML = value;
         lastHtmlRef.current = value; // Sync ref
      }
    }
  }, [value]);

  const handleInput = () => {
    if (editorRef.current) {
      const html = editorRef.current.innerHTML;
      lastHtmlRef.current = html; 
      onChange(html);
    }
  };

  const execCommand = (command: string, value: string | undefined = undefined) => {
    document.execCommand(command, false, value);
    if (editorRef.current) {
      editorRef.current.focus();
      const html = editorRef.current.innerHTML;
      lastHtmlRef.current = html;
      onChange(html);
    }
  };

  const insertTemplate = (content: string) => {
    if (editorRef.current) {
      editorRef.current.focus();
      const success = document.execCommand('insertHTML', false, content);

      if (!success) {
        editorRef.current.innerHTML += content;
      }

      const html = editorRef.current.innerHTML;
      lastHtmlRef.current = html;
      onChange(html);
      setShowTemplates(false);
    }
  };

  const themeColors = {
    indigo: 'border-indigo-100 focus-within:border-indigo-300 focus-within:ring-indigo-100',
    emerald: 'border-emerald-100 focus-within:border-emerald-300 focus-within:ring-emerald-100',
    amber: 'border-amber-100 focus-within:border-amber-300 focus-within:ring-amber-100',
    blue: 'border-blue-100 focus-within:border-blue-300 focus-within:ring-blue-100',
  };

  const buttonClass = "p-1.5 rounded hover:bg-slate-100 text-slate-500 hover:text-slate-700 transition-colors";

  return (
    <div className={`border rounded-xl bg-white overflow-hidden transition-all focus-within:ring-4 ${themeColors[colorTheme]}`}>
      {/* Toolbar */}
      <div className="flex items-center gap-1 p-2 border-b border-slate-100 bg-slate-50/50">
        <button onClick={() => execCommand('bold')} className={buttonClass} title="Negrito">
          <Bold size={16} />
        </button>
        <button onClick={() => execCommand('italic')} className={buttonClass} title="Itálico">
          <Italic size={16} />
        </button>
        <button onClick={() => execCommand('insertUnorderedList')} className={buttonClass} title="Lista">
          <List size={16} />
        </button>
        <div className="w-px h-4 bg-slate-300 mx-1"></div>

        {/* Templates Dropdown */}
        {templates.length > 0 && (
          <div className="relative">
            <button 
              onClick={() => setShowTemplates(!showTemplates)}
              className="flex items-center gap-1 px-2 py-1.5 rounded bg-white border border-slate-200 text-xs font-medium text-slate-600 hover:bg-slate-50 hover:text-blue-600 transition-colors shadow-sm"
            >
              <FilePlus size={14} /> Modelos <ChevronDown size={12} />
            </button>

            {showTemplates && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setShowTemplates(false)}></div>
                <div className="absolute top-full left-0 mt-1 w-56 bg-white rounded-lg shadow-xl border border-slate-100 z-20 py-1 overflow-hidden animate-fade-in-up">
                  {templates.map((t, idx) => (
                    <button
                      key={idx}
                      onClick={() => insertTemplate(t.content)}
                      className="w-full text-left px-4 py-2.5 text-xs text-slate-700 hover:bg-blue-50 hover:text-blue-700 transition-colors border-b border-slate-50 last:border-0"
                    >
                      {t.label}
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>
        )}
      </div>

      {/* Editable Area */}
      <div
        ref={editorRef}
        contentEditable
        onInput={handleInput}
        className="p-6 min-h-[160px] outline-none text-slate-700 text-sm leading-relaxed prose prose-sm max-w-none"
        style={{ whiteSpace: 'pre-wrap' }}
      />

      {/* Placeholder logic */}
      {!value && (
        <div className="absolute top-[52px] left-6 text-slate-300 text-sm pointer-events-none select-none">
          {placeholder}
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { api } from '../supabaseClient';
import { Appointment, Patient, User } from '../types';
import { ChevronLeft, ChevronRight, Plus, User as UserIcon, AlertCircle, Trash2, Edit2, Search, Printer, DollarSign } from 'lucide-react';
import { useAuth } from '../App';
import { useNavigate } from 'react-router-dom';
import { useDialog } from '../components/Dialog';

export default function CalendarPage() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const dialog = useDialog();
  const [date, setDate] = useState(new Date());
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [doctors, setDoctors] = useState<User[]>([]);
  const [selectedDoctor, setSelectedDoctor] = useState<string>('all');
  const [patients, setPatients] = useState<Patient[]>([]);

  const LOGO_URL = "https://i.ibb.co/n8rLsXSJ/upscalemedia-transformed-1.png";

  // Modal state
  const [showModal, setShowModal] = useState(false);
  const [error, setError] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);

  // Search State for Modal
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedPatientName, setSelectedPatientName] = useState('');

  const [newApt, setNewApt] = useState({ 
    patient_id: '', 
    doctor_id: '', 
    start_time: '09:00', 
    date: '', 
    type: 'first' as const,
    plan: 'particular',
    price: '' as any
  });

  useEffect(() => {
    fetchData();
    api.getUsers().then(({ data }) => {
        const allUsers = (data as User[]) || [];
        setDoctors(allUsers.filter((u:any) => u.role === 'doctor'));
    });
    api.getPatients().then(({ data }) => {
        setPatients((data as Patient[]) || []);
    });
  }, [date]);

  const fetchData = async () => {
    const dateStr = date.toISOString().split('T')[0];
    const { data } = await api.getAppointments(dateStr);
    setAppointments((data as Appointment[]) || []);
  };

  const handleDragStart = (e: React.DragEvent, aptId: string) => {
    e.dataTransfer.setData("aptId", aptId);
  };

  const handleDrop = async (e: React.DragEvent, time: string) => {
    const aptId = e.dataTransfer.getData("aptId");
    if (!aptId) return;

    const apt = appointments.find(a => a.id === aptId);
    if (!apt) return;

    const updated = { ...apt, start_time: time };
    setAppointments(prev => prev.map(p => p.id === aptId ? updated : p));

    await api.updateAppointment(aptId, { start_time: time });
  };

  const openModal = (apt?: Appointment) => {
    setError('');
    if (apt) {
        setEditingId(apt.id);
        setNewApt({
            patient_id: apt.patient_id,
            doctor_id: apt.doctor_id,
            start_time: apt.start_time,
            date: apt.date,
            type: apt.type as any,
            plan: apt.plan || 'particular',
            price: apt.price !== undefined ? apt.price : ''
        });
        setSelectedPatientName(apt.patient?.name || '');
        setSearchTerm('');
    } else {
        setEditingId(null);
        setNewApt({ 
          patient_id: '', 
          doctor_id: '', 
          start_time: '09:00', 
          date: date.toISOString().split('T')[0],
          type: 'first',
          plan: 'particular',
          price: ''
        });
        setSelectedPatientName('');
        setSearchTerm('');
    }
    setShowModal(true);
  };

  const handlePatientSelect = (p: Patient) => {
    setNewApt(prev => ({ ...prev, patient_id: p.id }));
    setSelectedPatientName(p.name);
    setSearchTerm('');
  };

  const handleDelete = async (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      const confirmed = await dialog.confirm("Excluir Consulta", "Tem certeza que deseja cancelar e excluir esta consulta?", "danger");
      if(!confirmed) return;

      setAppointments(prev => prev.filter(a => a.id !== id));

      try {
          await api.deleteAppointment(id);
      } catch (e) {
          dialog.alert("Erro", "Erro ao excluir consulta no banco de dados.");
          fetchData();
      }
  };

  // Helper to safely format YYYY-MM-DD to DD/MM/YYYY without timezone shift
  const formatSafeDate = (dateStr: string) => {
    if (!dateStr) return '';
    const parts = dateStr.split('-');
    if (parts.length === 3) return `${parts[2]}/${parts[1]}/${parts[0]}`;
    return dateStr;
  };

  const printAppointmentConfirmation = (apt: Appointment, e: React.MouseEvent) => {
    e.stopPropagation();
    const printWindow = window.open('', '_blank', 'width=800,height=600');
    if (!printWindow) {
      dialog.alert("Bloqueio", "Permita popups para imprimir.");
      return;
    }

    const docDate = new Date().toLocaleDateString('pt-BR');
    // FIX: Use safe formatter instead of new Date() for appointment date
    const aptDate = formatSafeDate(apt.date);
    const aptTime = apt.start_time;
    const doctorName = (doctors || []).find(d => d.id === apt.doctor_id)?.name || 'Médico Responsável';
    const attendantName = user?.name || 'Atendente';

    const htmlContent = `
      <!DOCTYPE html>
      <html lang="pt-BR">
      <head>
        <meta charset="UTF-8">
        <title>Comprovante de Agendamento</title>
        <script src="https://cdn.tailwindcss.com"></script>
        <style>
           body { font-family: sans-serif; padding: 2cm; }
           @media print { .no-print { display: none; } }
        </style>
      </head>
      <body class="bg-white text-slate-900">
        <div class="border-b-2 border-slate-900 pb-4 mb-8 flex justify-between items-center">
           <div class="flex items-center gap-3">
              <img src="${LOGO_URL}" alt="Genesis" class="h-10 w-auto" />
              <div>
                <h1 class="text-2xl font-bold uppercase tracking-wider">Genesis Medical</h1>
                <p class="text-xs text-slate-500">Comprovante de Agendamento</p>
              </div>
           </div>
           <div class="text-right text-sm">
             <p>Emitido em: <b>${docDate}</b></p>
           </div>
        </div>

        <div class="bg-slate-50 border border-slate-200 rounded-xl p-8 mb-8">
           <h2 class="text-xl font-bold text-blue-900 mb-6 border-b border-slate-200 pb-2">Detalhes da Consulta</h2>
           <div class="grid grid-cols-2 gap-6 text-sm">
              <div>
                 <p class="text-xs uppercase font-bold text-slate-500 mb-1">Paciente</p>
                 <p class="text-lg font-bold">${apt.patient?.name}</p>
                 <p class="text-slate-600">${apt.patient?.cpf || ''}</p>
              </div>
              <div>
                 <p class="text-xs uppercase font-bold text-slate-500 mb-1">Médico</p>
                 <p class="text-lg font-bold">Dr. ${doctorName}</p>
              </div>
              <div>
                 <p class="text-xs uppercase font-bold text-slate-500 mb-1">Data</p>
                 <p class="text-lg font-bold">${aptDate}</p>
              </div>
              <div>
                 <p class="text-xs uppercase font-bold text-slate-500 mb-1">Horário</p>
                 <p class="text-lg font-bold">${aptTime}</p>
              </div>
              <div>
                 <p class="text-xs uppercase font-bold text-slate-500 mb-1">Tipo</p>
                 <p class="capitalize">${apt.type === 'first' ? 'Primeira Consulta' : apt.type === 'return' ? 'Retorno' : 'Continuidade'}</p>
              </div>
           </div>
        </div>

        <div class="mt-20 space-y-12">
           <div class="flex justify-between gap-8">
              <div class="flex-1 border-t border-slate-400 pt-2 text-center">
                 <p class="font-bold text-sm">${apt.patient?.name}</p>
                 <p class="text-xs text-slate-500">Assinatura do Paciente</p>
              </div>
              <div class="flex-1 border-t border-slate-400 pt-2 text-center">
                 <p class="font-bold text-sm">${attendantName}</p>
                 <p class="text-xs text-slate-500">Atendente Responsável</p>
              </div>
           </div>

           <div class="w-1/2 mx-auto border-t border-slate-400 pt-2 text-center">
              <p class="font-bold text-sm">Dr. ${doctorName}</p>
              <p class="text-xs text-slate-500">Carimbo/Assinatura do Médico</p>
           </div>
        </div>

        <div class="mt-12 text-center text-[10px] text-slate-400">
           <p>Este comprovante deve ser apresentado na recepção no dia da consulta.</p>
           <p>Genesis Medical System</p>
        </div>

        <script>window.onload = () => window.print();</script>
      </body>
      </html>
    `;
    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  const handleCreateOrUpdate = async () => {
    setError('');

    if (!newApt.patient_id || !newApt.doctor_id || !newApt.date) {
      setError('Por favor, preencha todos os campos obrigatórios.');
      return;
    }

    try {
      const payload = {
        ...newApt,
        price: newApt.price ? parseFloat(newApt.price) : 0,
        status: 'scheduled'
      };

      if (editingId) {
          await api.updateAppointment(editingId, payload);
      } else {
          const { error: apiError } = await api.createAppointment(payload);
          if (apiError) throw apiError;
      }

      setShowModal(false);
      fetchData();
    } catch (err) {
      console.error(err);
      setError('Erro ao salvar.');
    }
  };

  const safeAppointments = appointments || [];

  const filteredAppointments = selectedDoctor === 'all' 
    ? safeAppointments 
