  name text not null,
  dob date,
  cpf text,
  contact text,
  social_info text,
  tags text[],
  anthropometrics jsonb default '{}'::jsonb,
  address jsonb default '{}'::jsonb,
  photo_url text,
  created_at timestamptz default now()
);

-- Fix Columns if missing
do $$ 
begin 
  if not exists (select 1 from information_schema.columns where table_name='patients' and column_name='photo_url') then 
    alter table patients add column photo_url text; 
  end if; 
  if not exists (select 1 from information_schema.columns where table_name='patients' and column_name='address') then 
    alter table patients add column address jsonb default '{}'::jsonb; 
  end if;
  if not exists (select 1 from information_schema.columns where table_name='anamneses' and column_name='status') then 
    alter table anamneses add column status text default 'final'; 
  end if;
  if not exists (select 1 from information_schema.columns where table_name='users' and column_name='crm') then 
    alter table users add column crm text; 
  end if;
end $$;

create table if not exists appointments (
  id uuid default gen_random_uuid() primary key,
  patient_id uuid references patients(id) on delete cascade,
  doctor_id uuid references users(id) on delete cascade,
  date date not null,
  start_time text not null,
  type text not null,
  plan text,
  price numeric,
  status text default 'scheduled',
  created_at timestamptz default now()
);

-- Fix Appointment Columns
do $$ 
begin 
  if not exists (select 1 from information_schema.columns where table_name='appointments' and column_name='plan') then 
    alter table appointments add column plan text; 
  end if;
  if not exists (select 1 from information_schema.columns where table_name='appointments' and column_name='price') then 
    alter table appointments add column price numeric; 
  end if;
end $$;

create table if not exists anamneses (
  id uuid default gen_random_uuid() primary key,
  patient_id uuid references patients(id) on delete cascade,
  doctor_id uuid references users(id) on delete cascade,
  soap jsonb not null,
  status text default 'final',
  created_at timestamptz default now()
);

create table if not exists documents (
  id uuid default gen_random_uuid() primary key,
  patient_id uuid references patients(id) on delete cascade,
  doctor_id uuid references users(id) on delete cascade,
  type text not null, -- 'prescription' or 'referral'
  content jsonb not null,
  created_at timestamptz default now()
);

create table if not exists messages (
  id uuid default gen_random_uuid() primary key,
  sender_id uuid references users(id) on delete cascade,
  receiver_id uuid references users(id) on delete cascade,
  content text not null,
  is_urgent boolean default false,
  created_at timestamptz default now()
);

-- Fix Messages Columns
do $$ 
begin 
  if not exists (select 1 from information_schema.columns where table_name='messages' and column_name='is_urgent') then 
    alter table messages add column is_urgent boolean default false; 
  end if;
end $$;

create table if not exists notifications (
  id uuid default gen_random_uuid() primary key,
  user_id uuid references users(id) on delete cascade,
  content text not null,
  read boolean default false,
  created_at timestamptz default now()
);

