-- 4. POWERFUL DELETE FUNCTIONS (RPC)
create or replace function delete_user_fully(target_id uuid)
returns void as $$
begin
  delete from notifications where user_id = target_id;
  delete from messages where sender_id = target_id or receiver_id = target_id;
  delete from appointments where doctor_id = target_id;
  delete from anamneses where doctor_id = target_id;
  delete from documents where doctor_id = target_id;
  delete from users where id = target_id;
end;
$$ language plpgsql security definer;

create or replace function delete_patient_fully(target_id uuid)
returns void as $$
begin
  delete from appointments where patient_id = target_id;
  delete from anamneses where patient_id = target_id;
  delete from documents where patient_id = target_id;
  delete from patients where id = target_id;
end;
$$ language plpgsql security definer;

-- 5. ENABLE REALTIME (Critical for Chat)
begin;
  drop publication if exists supabase_realtime;
  create publication supabase_realtime;
commit;
alter publication supabase_realtime add table messages, notifications;
`;

export const api = {
  // Users
  getUsers: async () => supabase.from('users').select('*'),
  createUser: async (user: any) => supabase.from('users').insert(user),
  updateUser: async (id: string, updates: any) => supabase.from('users').update(updates).eq('id', id),

  deleteUser: async (id: string) => {
    const { error } = await supabase.rpc('delete_user_fully', { target_id: id });
    if (error) {
      console.warn("RPC delete failed, trying manual...", error);
      await supabase.from('notifications').delete().eq('user_id', id);
      await supabase.from('messages').delete().or(`sender_id.eq.${id},receiver_id.eq.${id}`);
      await supabase.from('appointments').delete().eq('doctor_id', id);
      await supabase.from('anamneses').delete().eq('doctor_id', id);
      await supabase.from('documents').delete().eq('doctor_id', id);
      return await supabase.from('users').delete().eq('id', id);
    }
    return { error };
  },

  // Patients
  getPatients: async () => supabase.from('patients').select('*').order('name'),
  getPatient: async (id: string) => supabase.from('patients').select('*').eq('id', id).single(),
  createPatient: async (patient: any) => supabase.from('patients').insert(patient),
  updatePatient: async (id: string, updates: any) => supabase.from('patients').update(updates).eq('id', id),

  deletePatient: async (id: string) => {
     const { error } = await supabase.rpc('delete_patient_fully', { target_id: id });
     if (error) {
       console.warn("RPC delete failed, trying manual...", error);
       await supabase.from('appointments').delete().eq('patient_id', id);
       await supabase.from('anamneses').delete().eq('patient_id', id);
       await supabase.from('documents').delete().eq('patient_id', id);
       return await supabase.from('patients').delete().eq('id', id);
     }
     return { error };
  },

  // Appointments
  getAppointments: async (date?: string) => {
    let query = supabase.from('appointments').select('*, patient:patients(name), doctor:users(name)');
    if (date) query = query.eq('date', date);
    return query;
  },

  createAppointment: async (apt: any) => {
    if (apt.doctor_id) {
      await supabase.from('notifications').insert({
        user_id: apt.doctor_id,
        content: `Nova consulta marcada: ${apt.date} às ${apt.start_time}`,
      });
    }
    return supabase.from('appointments').insert(apt);
  },

  updateAppointment: async (id: string, updates: any) => supabase.from('appointments').update(updates).eq('id', id),
  deleteAppointment: async (id: string) => supabase.from('appointments').delete().eq('id', id),

  // Anamnesis
  getAnamneses: async (patientId: string) => 
    supabase.from('anamneses')
      .select('*, doctor:users(name, crm)')
      .eq('patient_id', patientId)
      .order('created_at', { ascending: false }),

  getAnamnesis: async (id: string) => supabase.from('anamneses').select('*').eq('id', id).single(),
  createAnamnesis: async (data: any) => supabase.from('anamneses').insert(data).select(), 
  updateAnamnesis: async (id: string, data: any) => supabase.from('anamneses').update(data).eq('id', id),
  deleteAnamnesis: async (id: string) => supabase.from('anamneses').delete().eq('id', id),

  // Documents
  getDocuments: async (patientId: string) => 
    supabase.from('documents')
      .select('*, doctor:users(name, crm)')
      .eq('patient_id', patientId)
      .order('created_at', { ascending: false }),

  createDocument: async (data: any) => supabase.from('documents').insert(data),
  deleteDocument: async (id: string) => supabase.from('documents').delete().eq('id', id),

  // Chat
  getMessages: async (user1: string, user2: string) => {
    return supabase
      .from('messages')
      .select('*, sender:users(name)')
      .or(`and(sender_id.eq.${user1},receiver_id.eq.${user2}),and(sender_id.eq.${user2},receiver_id.eq.${user1})`)
      .order('created_at', { ascending: true })
      .limit(100);
  },

  sendMessage: async (msg: any) => supabase.from('messages').insert(msg),
  deleteMessage: async (id: string) => supabase.from('messages').delete().eq('id', id),

  // Notifications
  getNotifications: async (userId: string) => 
    supabase.from('notifications')
      .select('*')
      .eq('user_id', userId)
      .eq('read', false)
      .order('created_at', { ascending: false }),

  markNotificationRead: async (id: string) => supabase.from('notifications').update({ read: true }).eq('id', id),
  markAllNotificationsRead: async (userId: string) => supabase.from('notifications').update({ read: true }).eq('user_id', userId),
};

import React, { useState, useRef } from 'react';
import { api } from '../supabaseClient';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Camera, Upload, AlertCircle, X, Check, MapPin, Search } from 'lucide-react';

export default function PatientCreate() {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [newP, setNewP] = useState({ 
    name: '', cpf: '', contact: '', dob: '', social_info: '', photo_url: '' 
  });

  // Address State
  const [address, setAddress] = useState({
    cep: '',
    street: '',
    number: '',
    complement: '',
    neighborhood: '',
    city: '',
    state: ''
  });
  const [loadingCep, setLoadingCep] = useState(false);

  // Webcam State
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);

  // Masks
  const maskCPF = (value: string) => {
    return value
      .replace(/\D/g, '')
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d{1,2})/, '$1-$2')
      .replace(/(-\d{2})\d+?$/, '$1');
  };

  const maskPhone = (value: string) => {
    return value
      .replace(/\D/g, '')
      .replace(/(\d{2})(\d)/, '($1) $2')
      .replace(/(\d{5})(\d)/, '$1-$2')
      .replace(/(-\d{4})\d+?$/, '$1');
  };

  const maskCEP = (value: string) => {
    return value.replace(/\D/g, '').replace(/(\d{5})(\d)/, '$1-$2').substring(0, 9);
  };

  const handleCepBlur = async () => {
    const cep = address.cep.replace(/\D/g, '');
    if (cep.length === 8) {
      setLoadingCep(true);
      try {
        const res = await fetch(`https://viacep.com.br/ws/${cep}/json/`);
        const data = await res.json();
        if (!data.erro) {
          setAddress(prev => ({
            ...prev,
            street: data.logradouro,
            neighborhood: data.bairro,
            city: data.localidade,
            state: data.uf
          }));
        }
      } catch (e) {
        console.error("Erro CEP", e);
      } finally {
        setLoadingCep(false);
      }
    }
  };

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: true });
      setStream(mediaStream);
      setIsCameraOpen(true);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (e) {
      alert("Não foi possível acessar a câmera. Verifique as permissões.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = () => {
    if (videoRef.current) {
      const canvas = document.createElement('canvas');
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(videoRef.current, 0, 0);
        const base64 = canvas.toDataURL('image/jpeg');
        setNewP({ ...newP, photo_url: base64 });
        stopCamera();
      }
    }
  };

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const payload = {
        name: newP.name,
        cpf: newP.cpf,
        contact: newP.contact,
        dob: newP.dob ? newP.dob : null,
        social_info: newP.social_info,
        photo_url: newP.photo_url || null,
        tags: [],
        anthropometrics: {},
        address: address
      };

      const { error: apiError } = await api.createPatient(payload);
      if (apiError) throw apiError;

      navigate('/patients');
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Erro ao criar paciente.');
    } finally {
      setLoading(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewP({ ...newP, photo_url: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6 animate-fade-in-up">
      <button onClick={() => navigate('/patients')} className="text-slate-500 hover:text-blue-900 flex items-center gap-2 transition-colors">
        <ArrowLeft size={20} /> Voltar para lista
      </button>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="bg-slate-50 p-6 border-b border-slate-200">
          <h2 className="text-2xl font-bold text-slate-900">Novo Paciente</h2>
          <p className="text-slate-500 text-sm">Preencha os dados abaixo para cadastrar um novo paciente.</p>
        </div>

        <form onSubmit={handleCreate} className="p-8 space-y-8">
          {error && (
            <div className="bg-red-50 text-red-600 p-4 rounded-lg flex items-center gap-2 text-sm border border-red-100">
              <AlertCircle size={16} />
              {error}
            </div>
          )}

          {/* Photo Section */}
          <div className="flex flex-col items-center justify-center space-y-4">

            {isCameraOpen ? (
              <div className="relative w-64 h-48 bg-black rounded-xl overflow-hidden shadow-lg">
                <video ref={videoRef} autoPlay muted className="w-full h-full object-cover" onLoadedMetadata={() => videoRef.current?.play()} />
                <div className="absolute bottom-4 left-0 right-0 flex justify-center gap-4">
                  <button type="button" onClick={stopCamera} className="bg-red-500 p-2 rounded-full text-white hover:bg-red-600"><X size={20}/></button>
                  <button type="button" onClick={capturePhoto} className="bg-green-500 p-2 rounded-full text-white hover:bg-green-600"><Check size={20}/></button>
                </div>
              </div>
            ) : (
              <div className="relative w-32 h-32 rounded-full bg-slate-100 border-4 border-white shadow-lg overflow-hidden group">
                {newP.photo_url ? (
                  <img src={newP.photo_url} alt="Preview" className="w-full h-full object-cover" />
                ) : (
                  <div className="flex items-center justify-center w-full h-full text-slate-300">
                    <Camera size={40} />
                  </div>
                )}

                <div className="absolute inset-0 bg-black/40 hidden group-hover:flex items-center justify-center transition-all cursor-pointer flex-col gap-2">
                   <button type="button" onClick={startCamera} className="text-white text-xs font-medium flex flex-col items-center hover:text-blue-200">
                     <Camera size={20} className="mb-1"/> Tirar Foto
                   </button>
                   <label className="cursor-pointer text-white flex flex-col items-center text-xs font-medium hover:text-blue-200">
                    <Upload size={20} className="mb-1"/> Upload
                    <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
                   </label>
                </div>
              </div>
            )}

            {!isCameraOpen && (
              <div className="flex gap-4 text-sm font-medium">
                 <button type="button" onClick={startCamera} className="text-blue-600 hover:text-blue-800 flex items-center gap-1">
                   <Camera size={16}/> Tirar Foto
                 </button>
                 <label className="text-blue-600 hover:text-blue-800 flex items-center gap-1 cursor-pointer">
                   <Upload size={16}/> Upload
                   <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
                 </label>
              </div>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Nome Completo *</label>
              <input required 
                className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all" 
                value={newP.name} onChange={e => setNewP({...newP, name: e.target.value})} placeholder="Ex: João da Silva"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">CPF</label>
              <input 
                className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all" 
                value={newP.cpf} 
                onChange={e => setNewP({...newP, cpf: maskCPF(e.target.value)})} 
                placeholder="000.000.000-00"
                maxLength={14}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data de Nascimento *</label>
              <input type="date" required 
                className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all" 
                value={newP.dob} onChange={e => setNewP({...newP, dob: e.target.value})} 
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Contato</label>
              <input 
                className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all" 
                value={newP.contact} 
                onChange={e => setNewP({...newP, contact: maskPhone(e.target.value)})} 
                placeholder="(81) 9.9999-9999"
                maxLength={16}
              />
            </div>

            {/* Address Section */}
            <div className="md:col-span-2 border-t border-slate-100 pt-4 mt-2">
               <h3 className="font-semibold text-slate-800 mb-4 flex items-center gap-2"><MapPin size={18} className="text-blue-900"/> Endereço</h3>
               <div className="grid grid-cols-6 gap-4">
                  <div className="col-span-2">
                     <label className="block text-sm font-medium text-slate-700 mb-1">CEP</label>
                     <div className="relative">
                        <input 
                          className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all" 
                          value={address.cep} 
                          onChange={e => setAddress({...address, cep: maskCEP(e.target.value)})} 
                          onBlur={handleCepBlur}
                          placeholder="00000-000"
                        />
                        {loadingCep && <div className="absolute right-3 top-1/2 -translate-y-1/2 animate-spin text-blue-900"><Search size={14}/></div>}
                     </div>
                  </div>
                  <div className="col-span-4">
                     <label className="block text-sm font-medium text-slate-700 mb-1">Rua / Logradouro</label>
                     <input 
                       className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all" 
                       value={address.street} 
                       onChange={e => setAddress({...address, street: e.target.value})} 
                     />
                  </div>
                  <div className="col-span-2">
                     <label className="block text-sm font-medium text-slate-700 mb-1">Número</label>
                     <input 
                       className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all" 
                       value={address.number} 
                       onChange={e => setAddress({...address, number: e.target.value})} 
                     />
                  </div>
                  <div className="col-span-4">
                     <label className="block text-sm font-medium text-slate-700 mb-1">Bairro</label>
                     <input 
                       className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all" 
                       value={address.neighborhood} 
                       onChange={e => setAddress({...address, neighborhood: e.target.value})} 
                     />
                  </div>
                  <div className="col-span-4">
                     <label className="block text-sm font-medium text-slate-700 mb-1">Cidade</label>
                     <input 
                       className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all" 
                       value={address.city} 
                       onChange={e => setAddress({...address, city: e.target.value})} 
                     />
                  </div>
                  <div className="col-span-2">
                     <label className="block text-sm font-medium text-slate-700 mb-1">UF</label>
                     <input 
                       className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all" 
                       value={address.state} 
                       onChange={e => setAddress({...address, state: e.target.value})} 
                       maxLength={2}
                     />
                  </div>
               </div>
            </div>

            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Informações Sociais</label>
              <textarea rows={4} 
                className="w-full px-4 py-2.5 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-900 outline-none transition-all resize-none" 
                value={newP.social_info} onChange={e => setNewP({...newP, social_info: e.target.value})} 
                placeholder="Descreva o contexto social, familiar e profissional..." 
              />
            </div>
          </div>

          <div className="pt-4 flex gap-4 border-t border-slate-100">
            <button type="button" onClick={() => navigate('/patients')} className="flex-1 py-3 bg-slate-100 rounded-lg text-slate-700 font-medium hover:bg-slate-200 transition-colors">Cancelar</button>
            <button disabled={loading} type="submit" className="flex-1 py-3 bg-blue-900 rounded-lg text-white font-medium hover:bg-blue-800 transition-colors shadow-lg shadow-blue-900/20">
              {loading ? 'Cadastrando...' : 'Cadastrar Paciente'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

