import React, { Component, ErrorInfo, ReactNode } from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: any;
}

// Componente de segurança para capturar erros e evitar tela branca total
class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState;

  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      error: null
    };
  }

  static getDerivedStateFromError(error: any): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: any, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{
          height: '100vh', 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center', 
          justifyContent: 'center', 
          backgroundColor: '#f8fafc',
          color: '#0f172a',
          fontFamily: 'system-ui, sans-serif',
          padding: '20px',
          textAlign: 'center'
        }}>
          <div style={{ maxWidth: '500px', width: '100%' }}>
            <div style={{ fontSize: '48px', marginBottom: '20px' }}>🤕</div>
            <h1 style={{ fontSize: '24px', fontWeight: 'bold', marginBottom: '10px' }}>Ops! Algo deu errado.</h1>
            <p style={{ color: '#64748b', marginBottom: '20px' }}>O sistema encontrou um erro inesperado e precisou parar.</p>

            <div style={{ 
              backgroundColor: '#fee2e2', 
              color: '#991b1b', 
              padding: '15px', 
              borderRadius: '8px', 
              fontSize: '12px', 
              textAlign: 'left',
              overflow: 'auto',
              maxHeight: '150px',
              marginBottom: '20px',
              border: '1px solid #fecaca'
            }}>
              {this.state.error?.toString()}
            </div>

            <button 
              onClick={() => { 
                localStorage.clear(); 
                window.location.reload(); 
              }} 
              style={{
                backgroundColor: '#0f172a',
                color: 'white',
                border: 'none',
                padding: '12px 24px',
                borderRadius: '8px',
                fontSize: '16px',
                fontWeight: '600',
                cursor: 'pointer',
                boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
              }}
            >
              Limpar Dados e Recarregar
            </button>
          </div>
        </div>
      );
    }

    return this.props.children || null;
  }
}

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  </React.StrictMode>
);

export enum UserRole {
  ADMIN = 'admin',
  DOCTOR = 'doctor',
  RECEPTIONIST = 'receptionist'
}

export interface User {
  id: string;
  username: string;
  name: string;
  role: UserRole;
  crm?: string; // Doctor's medical license number
  created_at?: string;
}

export interface Address {
  cep: string;
  street: string;
  number: string;
  complement?: string;
  neighborhood: string;
  city: string;
  state: string;
}

export interface Patient {
  id: string;
  name: string;
  dob: string; // YYYY-MM-DD
  cpf: string;
  contact: string;
  social_info: string;
  address?: Address; // New Address field
  tags?: string[]; // stored as text[] in supabase
  anthropometrics?: Anthropometrics;
  photo_url?: string; // Base64 string or URL
}

export interface Anthropometrics {
  weight?: number;
  height?: number;
  bmi?: number;
  bp_systolic?: number;
  bp_diastolic?: number;
}

export interface Appointment {
  id: string;
  patient_id: string;
  doctor_id: string;
  date: string; // YYYY-MM-DD
  start_time: string; // HH:mm
  type: 'first' | 'return' | 'continuity';
  plan?: string; // 'particular', 'unimed', etc.
  price?: number;
  status: 'scheduled' | 'completed' | 'cancelled';
  patient?: Patient; // Joined
  doctor?: User; // Joined
}

export interface Anamnesis {
  id: string;
  patient_id: string;
  doctor_id: string;
  soap: {
    s: string;
    o: string;
    a: string;
    p: string;
  };
  status: 'draft' | 'final';
  created_at: string;
  doctor?: User;
}

export interface PrescriptionItem {
  medication: string;
  quantity: string;
  dosage: string;
  usageMode?: string; // e.g., 'Uso Oral', 'Uso Tópico'
}

export interface MedicalDocument {
  id: string;
  patient_id: string;
  doctor_id: string;
  type: 'prescription' | 'referral'; // Receituário ou Encaminhamento
  content: {
    items?: PrescriptionItem[]; // Para receituário
    text?: string; // Para encaminhamento (HTML Rich Text)
  }; 
  created_at: string;
  doctor?: User;
}

export interface Message {
  id: string;
  sender_id: string;
  sender_name?: string;
  receiver_id?: string; // Null for public channel
  content: string;
  is_urgent?: boolean;
  created_at: string;
}

export interface Notification {
  id: string;
  user_id: string;
  content: string;
  read: boolean;
  created_at: string;
}

import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { api } from '../supabaseClient';
import { Patient, Anamnesis, UserRole, MedicalDocument, PrescriptionItem } from '../types';
import { useAuth } from '../App';
import { Printer, Activity, Tag, Camera, ArrowLeft, FileText, PlusCircle, Pencil, Trash2, Loader, Eye, X, Upload, Check, FilePlus, ScrollText, MapPin, ChevronDown } from 'lucide-react';
import { useDialog } from '../components/Dialog';
import RichTextEditor from '../components/RichTextEditor';

export default function PatientProfile() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const dialog = useDialog();
  const [patient, setPatient] = useState<Patient | null>(null);
  const [history, setHistory] = useState<Anamnesis[]>([]);
  const [documents, setDocuments] = useState<MedicalDocument[]>([]);
  const [activeTab, setActiveTab] = useState<'details' | 'anamnesis' | 'documents'>('details');
  const [loadingDelete, setLoadingDelete] = useState<string | null>(null);

  // View Modal State
  const [viewAnamnesis, setViewAnamnesis] = useState<Anamnesis | null>(null);

  // Document Modal State
  const [showDocModal, setShowDocModal] = useState(false);
  const [docType, setDocType] = useState<'prescription' | 'referral'>('prescription');

  // Prescription State
  const [prescriptionItems, setPrescriptionItems] = useState<PrescriptionItem[]>([{ medication: '', quantity: '', dosage: '', usageMode: 'Uso Oral' }]);

  // Referral State
  const [referralText, setReferralText] = useState('');

  // Webcam State
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);

  const [newTags, setNewTags] = useState('');
  const [anthropo, setAnthropo] = useState({ weight: '', height: '', bp_s: '', bp_d: '' });

  const LOGO_URL = "https://i.ibb.co/n8rLsXSJ/upscalemedia-transformed-1.png";
  const HEADER_LOGO_URL = "https://i.ibb.co/sJR9zQKt/upscalemedia-transformed-1.png";

  const USAGE_MODES = [
    'Uso Oral',
    'Uso Tópico',
    'Uso Endovenoso',
    'Uso Intramuscular',
    'Uso Subcutâneo',
    'Uso Intranasal',
    'Uso Oftálmico',
    'Uso Otológico',
    'Uso Retal',
    'Uso Vaginal',
    'Uso Inalatório',
    'Uso Contínuo',
    'Outro'
  ];

  const fetchHistory = async () => {
    if (id && user?.role === UserRole.DOCTOR) {
      const { data } = await api.getAnamneses(id);
      setHistory((data as any) || []);

      const { data: docs } = await api.getDocuments(id);
      setDocuments((docs as any) || []);
    }
  };

  useEffect(() => {
    if (id) {
      api.getPatient(id).then(({ data }) => setPatient(data as any));
      fetchHistory();
    }
  }, [id, user]);

  // Camera Cleanup on Unmount
  useEffect(() => {
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [stream]);

  const handleUpdateBio = async () => {
    if (!id || !patient) return;

    const currentTags = patient.tags || [];
    const addedTags = newTags.split(',').map(t => t.trim()).filter(Boolean);
    const updatedTags = [...new Set([...currentTags, ...addedTags])];

    const updatedAnthropo = {
      ...patient.anthropometrics,
      weight: Number(anthropo.weight) || patient.anthropometrics?.weight,
      height: Number(anthropo.height) || patient.anthropometrics?.height,
      bp_systolic: Number(anthropo.bp_s) || patient.anthropometrics?.bp_systolic,
      bp_diastolic: Number(anthropo.bp_d) || patient.anthropometrics?.bp_diastolic,
      bmi: (Number(anthropo.weight) && Number(anthropo.height)) 
        ? Number((Number(anthropo.weight) / ((Number(anthropo.height)/100) ** 2)).toFixed(2))
        : patient.anthropometrics?.bmi
    };

    await api.updatePatient(id, {
      tags: updatedTags,
      anthropometrics: updatedAnthropo
    });

    const { data } = await api.getPatient(id);
    if(data) setPatient(data as any);
    setNewTags('');
    setAnthropo({ weight: '', height: '', bp_s: '', bp_d: '' });
    await dialog.alert("Sucesso", "Os dados antropométricos e tags foram atualizados com sucesso!");
  };

  const updatePhoto = async (base64: string) => {
     if(id) {
        await api.updatePatient(id, { photo_url: base64 });
        setPatient(prev => prev ? ({ ...prev, photo_url: base64 }) : null);
     }
  };

  const handlePhotoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && id) {
      const reader = new FileReader();
      reader.onloadend = async () => {
        await updatePhoto(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: true });
      setStream(mediaStream);
      setIsCameraOpen(true);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (e) {
      dialog.alert("Erro", "Não foi possível acessar a câmera.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = () => {
    if (videoRef.current) {
      const canvas = document.createElement('canvas');
      canvas.width = videoRef.current.videoWidth;
      canvas.height = videoRef.current.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(videoRef.current, 0, 0);
        const base64 = canvas.toDataURL('image/jpeg');
        updatePhoto(base64);
        stopCamera();
      }
    }
  };

  const handleDeleteAnamnesis = async (anamnesisId: string) => {
    const confirmed = await dialog.confirm("Excluir Rascunho", "Deseja excluir este rascunho permanentemente?", "danger");
    if (!confirmed) return;

    setLoadingDelete(anamnesisId);
    try {
      await api.deleteAnamnesis(anamnesisId);
      setHistory(prev => prev.filter(h => h.id !== anamnesisId));
    } catch (e) {
      dialog.alert("Erro", "Não foi possível excluir o rascunho.");
    } finally {
      setLoadingDelete(null);
    }
  };

  const handleDeleteDocument = async (docId: string) => {
    const confirmed = await dialog.confirm("Excluir Documento", "Deseja excluir este documento permanentemente?", "danger");
    if (!confirmed) return;

    setLoadingDelete(docId);
    try {
      await api.deleteDocument(docId);
      setDocuments(prev => prev.filter(d => d.id !== docId));
    } catch (e) {
      dialog.alert("Erro", "Não foi possível excluir.");
    } finally {
      setLoadingDelete(null);
    }
  };

  const handleEditAnamnesis = (anamnesisId: string) => {
    navigate(`/anamnesis/session/${id}?editId=${anamnesisId}`);
  };

  // Helper for date formatting without timezone shift
  const formatSafeDate = (dateStr: string) => {
    if(!dateStr) return 'N/A';
    const parts = dateStr.split('-');
    if(parts.length === 3) return `${parts[2]}/${parts[1]}/${parts[0]}`;
    return dateStr;
  }

  const handlePrint = (anamnesis: Anamnesis) => {
    if (!patient) return;
    const printWindow = window.open('', '_blank', 'width=900,height=800');
    if (!printWindow) {
